const item = $input.first();
const body = item?.json?.body && typeof item.json.body === 'object' ? item.json.body : {};
const root = item?.json ?? {};

const rawSlug = body.project_slug ?? body.slug ?? root.project_slug ?? root.slug;
const rawName = body.project_name ?? body.name ?? root.project_name ?? root.name;

if (typeof rawSlug !== 'string' || rawSlug.trim() === '') {
  throw new Error('Missing or invalid project_slug');
}

const project_slug = rawSlug.trim();
const project_name = typeof rawName === 'string' && rawName.trim() !== ''
  ? rawName.trim()
  : project_slug;

return [{
  json: {
    project_slug,
    project_name
  }
}];
